-- Enrichment marathon batch: LanguageTool, LastPass, Latenode, Later, Lattice, LaunchDarkly, Lavender, Lavu

-- ── LanguageTool ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LanguageTool is an open-source, AI-powered grammar, spelling and style checker supporting 30-plus languages across browsers, desktop apps and an API.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Premium from about $4.17/month billed every 2 years)$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Potsdam, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Portuguese$q$, $q$Dutch$q$, $q$Italian$q$, $q$Polish$q$, $q$Russian$q$, $q$Ukrainian$q$, $q$Chinese$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$LanguageTool Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LanguageTool review 2026: see how this open-source, multilingual grammar and style checker compares on features, pricing tiers and Grammarly alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LanguageTool is an open-source, multilingual grammar, style and spell-checking platform that began in 2003 as a diploma-thesis project by German computational linguist Daniel Naber, who built the original rule-based checking engine and released it as free, open-source software; over the following two decades the project grew into a commercial company headquartered in Potsdam, Germany, employing roughly 29 people as a remote-first team, and in April 2023 LanguageTool was acquired by Learneo, an edtech holding company that also owns Course Hero and LitCharts, while the open-source core engine remains publicly available on GitHub. Architecturally, LanguageTool combines a large rule-based grammar engine (tens of thousands of hand-written and community-contributed rules) with statistical and neural machine-learning models for detecting style issues and word choice, and its most advanced paraphrasing and rewriting features are powered by generative AI; this hybrid approach differentiates it from purely neural competitors and lets the free, offline-capable core still catch a wide range of mistakes without a live AI backend. The product ships as a website checker, browser add-ons for Chrome, Firefox, Edge and Safari, desktop apps for Windows, macOS and Linux, mobile keyboards for Android and iOS, native integrations for Google Docs, Microsoft Word and Outlook, and OpenOffice/LibreOffice, alongside a developer-facing HTTP API and a self-hostable server package that lets businesses run LanguageTool on their own infrastructure for data-privacy reasons. LanguageTool checks grammar, spelling, punctuation and style across more than 30 languages and regional variants, each maintained largely by volunteer native-speaker linguists, and Premium subscribers unlock more than 20,000 additional checking rules, a 150,000-character-per-text limit (versus 2,000 characters free), unlimited AI-powered sentence paraphrasing (the free tier allows only a few paraphrases per day), a custom style guide for enforcing preferred terminology, and full access to every supported language. Pricing is structured around an Individual Premium plan billed in several cycles: monthly at roughly $24.90 (EUR19.90), quarterly at about $12/month, annually at about $7/month (EUR59.89/year), and a discounted two-year plan at around $4.17/month (EUR99.90 for two years); a Teams plan covers 2 to 20-plus members and layers on centralized billing, a shared Team Style Guide and a Team Dictionary for organization-specific terminology; and a Business tier serves larger organizations needing admin controls or on-premise deployment. The free Basic plan remains genuinely usable, covering core grammar and spelling checks with a 2,000-character limit and three free paraphrases per day, a more generous free offering than most rivals provide. LanguageTool's target audience spans individual writers, students and non-native English speakers who want multilingual support beyond English-only tools, plus businesses, publishers and software teams that need to embed grammar checking via API or want a self-hosted, privacy-compliant alternative to cloud-only competitors. Its most direct competitor is Grammarly, which has far greater brand recognition, a larger AI-writing feature set and deeper US-market penetration but is closed-source, English-centric, and has no true offline or self-hosted option; LanguageTool differentiates on open-source transparency, self-hosting for data-sensitive customers, and best-in-class support for European and non-English languages. Other competitors include ProWritingAid, which focuses on long-form style analytics popular with fiction authors; Ginger Software, which bundles translation and text-to-speech; Wordtune, which emphasizes AI rewriting over rule-based checking; and Microsoft Editor, bundled into Word and Outlook. LanguageTool's open-source roots continue to matter commercially: the community-maintained GitHub project feeds new rules and language support back into the commercial product, and organizations with strict data-residency requirements can deploy the engine on their own servers rather than sending text to a third-party cloud, a capability few closed-source competitors offer in the same way.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '917d6a1d-804c-4ce5-b0e0-d9db22f252c6';

