-- ── Latenode ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Latenode is a no-code and low-code workflow automation platform combining a visual builder with full custom JavaScript, AI agents and 1,200+ integrations.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (usage-based)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pay-as-you-go usage-based pricing beyond free CPU-seconds)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Latenode Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Latenode review 2026: see how this code-friendly automation platform's CPU-second pricing, AI agents and 1,200+ integrations compare to Zapier and Make.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Latenode is a workflow automation platform founded in 2022 by a bootstrapped, remote-first team that says it draws on more than nine years of hands-on automation experience running its founders' own businesses; the company has not disclosed institutional venture funding and positions itself as an independently funded, product-led alternative built to address complaints long-time users have with Zapier's per-task pricing and n8n's self-hosting and maintenance burden. Architecturally, Latenode is a hybrid no-code/low-code automation engine: workflows are built visually as connected nodes, similar to Zapier, Make or n8n, but every node can be extended or replaced with full custom JavaScript, including the ability to import NPM packages directly inside a node, giving technical users the flexibility of a scripting environment without leaving the visual canvas; this lets a single platform serve non-technical operators who just want to connect apps as well as developers who need loops, conditional branching or bespoke API logic that off-the-shelf connectors do not support. The platform connects to more than 1,200 named apps and over 5,500 total integrations, and it embeds native access to large language models including GPT, Claude and Gemini directly inside workflow nodes, alongside a drag-and-drop AI-agent builder for constructing multi-step autonomous agents, a built-in headless browser for web scraping and browser automation, built-in NoSQL databases and global variables for storing workflow state, and retrieval-augmented generation (RAG) storage for grounding AI responses in a company's own documents. Enterprise-oriented capabilities include SOC 2 alignment, single sign-on, role-based access control and GDPR alignment. Latenode's pricing model is unusual in the automation category: rather than billing per 'operation' or 'task' the way Zapier and Make do, Latenode meters actual CPU execution seconds, so a workflow that finishes in five seconds costs the same regardless of how many nodes or steps it contains, which the company markets as making costs predictable and, at high volume, substantially cheaper than Zapier. The Free plan includes 10,000 CPU-seconds per month, up to five active workflows, one execution worker, a 3-minute execution time limit, 3-day execution history, and access to the full visual builder, all app integrations, an AI Code Copilot trial, the AI Agent node, one RAG storage instance, webhooks, browser automation and the built-in database - core platform capabilities are not locked behind higher tiers. The Pay-as-you-Go plan has no fixed monthly base fee and includes the same 10,000 free CPU-seconds, then charges on a declining tiered rate starting at $0.00012 per CPU-second for the next 90,000 seconds and dropping as low as $0.00005 per CPU-second beyond 5 million seconds per month, while also raising limits to unlimited workflows and executions, five execution workers, a 10-minute execution time limit and 30-day execution history; illustrative examples the company publishes include roughly $10.80/month for 100,000 short one-second workflow runs and roughly $83.80/month for 100,000 heavier ten-second runs. Optional add-ons let teams buy additional reserved execution workers, higher file-size limits, longer execution time windows, shorter polling intervals and extra RAG storage instances, while a separate 'Plug-n-Play' (PnP) token system, priced at $1 per token, pays for premium provider nodes such as certain AI models, file converters, enrichment tools, or persistent authenticated connections to platforms like Telegram, WhatsApp and LinkedIn. A custom Enterprise plan is available for organizations with larger compliance or volume needs. Latenode's target audience spans solo founders and growth/marketing teams automating repetitive tasks, technical operations and engineering teams that need custom logic beyond simple app-to-app triggers, and AI-forward teams building agentic workflows that combine LLM calls, data retrieval and multi-step orchestration. Its core competitors are Zapier, the market leader known for the broadest app catalog and simplicity but criticized for expensive per-task pricing at scale; Make (formerly Integromat), which offers a similarly visual, branching scenario builder popular with operations teams; and n8n, an open-source, self-hostable automation tool favored by developers who want full infrastructure control but must manage hosting and maintenance themselves. Latenode differentiates itself by combining n8n-style code flexibility with Zapier-style hosted simplicity and a transparent, execution-time-based pricing model designed to stay predictable as usage scales.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f977f684-1fe1-4506-a3eb-4159d62fd97f';

