-- ── Lattice ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lattice is a people management platform for performance reviews, goal-setting and OKRs, engagement surveys and career growth used by HR and people teams.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise per-seat subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (modules from about $4/seat/month; $4,000 minimum annual spend)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lattice Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lattice review 2026: pricing modules, performance and OKR features, and how this people-management platform compares to Culture Amp and 15Five.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lattice is a people-management and performance platform founded in 2015 in San Francisco by Jack Altman and Eric Koslow, built originally around continuous performance reviews and goal-setting as an alternative to once-a-year, spreadsheet-driven HR review cycles; the company went through Y Combinator and grew into one of the best-known 'people ops' companies, raising a total of roughly $329.3 million in venture funding, including a $175 million Series F in January 2022 led by Dragoneer Investment Group with participation from Tiger Global, Founders Fund, Thrive Capital, Shasta Ventures and Khosla Ventures, as well as individual investors such as Salesforce CEO Marc Benioff and Reddit co-founder Alexis Ohanian, which tripled the company's valuation to about $3 billion. Jack Altman (brother of OpenAI CEO Sam Altman) stepped down as Lattice's CEO in 2024 while remaining chairman of the board, and in 2025 Lattice announced it would sunset the HRIS and payroll products it had expanded into, choosing instead to refocus on its original core strength of performance management, goals and engagement rather than compete as a full human-resources-information-system provider. Architecturally, Lattice is a cloud-based SaaS platform organized around modular products that share a common data layer: 1:1 meeting notes, weekly check-ins, peer feedback and Q&A boards run underneath all products as connective tissue, while an AI Agent - rolled out to all customers at no additional cost - sits across the platform to auto-generate meeting notes, coaching suggestions, review drafts, and plain-language analytics queries that return charts pulled from Lattice's Analytics engine. The core purchasable modules are Performance (structured performance reviews, succession planning, promotion and PIP workflows, calibration and talent review tools), Goals and OKRs (cascading company-to-individual goal trees, progress tracking, and integrations with tools like Salesforce and Jira), and Engagement (pulse surveys, onboarding/exit surveys, eNPS tracking, and AI-generated trend analysis), each of which can be purchased individually or combined, plus two add-on modules: Compensation (comp bands, benchmarking, and multi-step approval workflows for pay cycles) and Grow (competency frameworks, individual development plans, and career-track mapping). Pricing is per-seat, billed annually in USD only, with a $4,000 minimum annual contract value and dedicated human support included on every contract; list prices are approximately $10/seat/month for Performance, $8/seat/month for Goals and OKRs, $4/seat/month for Engagement, plus $6/seat/month for the Compensation add-on and $4/seat/month for the Grow add-on, while the most popular bundled option, Foundations (Performance plus Goals and OKRs together), lists at roughly $13/seat/month. There is no self-serve free trial; prospective customers must go through a sales-assisted demo process to see pricing tailored to their headcount and module mix. Lattice's target customers are mid-market to enterprise HR and people-operations teams, typically at companies from roughly 50 to several thousand employees, that want a unified system for performance reviews, OKRs and engagement surveys rather than stitching together point solutions, with particular strength among fast-growing technology companies that adopted Lattice during its early YC-network growth phase. Its principal competitors include Culture Amp, generally viewed as stronger on engagement analytics and people-science research; 15Five, which competes more directly on lightweight, manager-friendly continuous performance check-ins at a lower price point; Leapsome, which emphasizes tightly integrated OKRs and structured 1:1s; and Betterworks, which focuses specifically on enterprise goal-management and OKR software. Lattice differentiates itself through its combined performance-plus-engagement-plus-goals suite under one platform, its AI Agent embedded directly into manager workflows, and its pedigree as one of the original companies that popularized continuous performance management as a category, even as it has narrowed its scope away from full HRIS/payroll competition with providers like Rippling, Gusto and Workday.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '347340e4-2920-47db-a757-9978b6eb89a7';

