-- ── LaunchDarkly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LaunchDarkly is a feature management and experimentation platform that lets engineering teams control feature flags, rollouts and AI agent behavior at runtime.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Free (Developer plan); Foundation from $10/month per service connection$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$Oakland, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LaunchDarkly Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LaunchDarkly review 2026: feature flag and AI agent control pricing, key features, and how it compares to Split, Optimizely and open-source alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LaunchDarkly is a feature-management and runtime-control platform founded in 2014 in Oakland, California by Edith Harbaugh and John Kodumal, two Harvey Mudd College classmates who identified the same problem from opposite vantage points - Harbaugh as a product manager at TripIt, Kodumal as an engineer at Atlassian who had built an internal feature-flagging system - and concluded that small and mid-sized engineering teams needed an externally hosted alternative to the custom feature-flag infrastructure that only companies like Amazon, Facebook and Netflix could afford to build in-house; the company was reportedly rejected by Y Combinator and by roughly 30 venture capital firms before finding early traction with developers outside Silicon Valley. LaunchDarkly went on to raise approximately $330 million in total funding, including a $200 million Series D in August 2021 led in part by Bessemer Venture Partners, Redpoint Ventures and 500 Global that tripled its valuation to roughly $3 billion, making it a feature-management unicorn roughly seven years after founding; the company now employs around 640 people and remains headquartered in Oakland. Architecturally, LaunchDarkly's core product, CodeControl, works by wrapping conditional logic in a customer's application code inside feature flags evaluated through LaunchDarkly's SDKs, available for roughly 30 languages and frameworks; flag state and targeting rules are distributed to a global streaming infrastructure so that flags can be toggled, rolled out to specific user segments, or instantly rolled back without a code redeploy, and the platform layers in A/B testing and experimentation, session replay, and audit-logged approval workflows for regulated environments. In response to the rise of AI-native software, LaunchDarkly has extended the same runtime-control model into a companion product called AgentControl, designed to govern the behavior of AI agents and LLM-powered features in production - tracking 'AI runs' (each LLM request or automated online evaluation counts as one run), enabling kill-switches, guardrails and staged rollouts for AI features the same way CodeControl does for traditional code. LaunchDarkly's pricing spans four tiers under a combined 'Full Platform' (CodeControl plus AgentControl) structure: a free Developer plan offers unlimited seats, 10 million logs and traces, unlimited feature flags, A/B tests and experiments, 5,000 session replays/error events, unlimited playgrounds and offline evaluations, 5,000 AI runs per month, and 14-day data retention, with no credit card required; the Foundation plan, billed yearly, adds user/account/device targeting, unlimited projects, single sign-on and 30-day retention, priced around $10/month per service connection plus roughly $8.33/month per 1,000 client-side monthly active users for CodeControl, with AgentControl overage priced at $5 per 1,000 AI runs beyond the free 5,000/month allotment; Enterprise is custom-priced and adds advanced targeting, release automation, scheduling and approval workflows, SAML/SCIM, custom roles, and 100-plus day retention; and the top-tier Guardian plan is also custom-priced and adds automated release monitoring, guardrail metrics, proactive failure alerts, and automatic pause-or-rollback of risky releases, aimed at the most safety-critical deployment environments. LaunchDarkly's target audience is primarily software engineering and platform teams at technology companies of all sizes, from startups on the free Developer tier to large enterprises running thousands of flags across regulated industries such as finance and healthcare that need audit trails and staged, reversible releases; more recently the AgentControl product also targets AI/ML platform teams that need production guardrails around autonomous or LLM-driven features. Its main competitors include Split (a feature-flagging and experimentation platform acquired by Harness), Optimizely (which combines feature flagging with broader digital experience experimentation), open-source alternatives Flagsmith and Unleash that appeal to teams wanting self-hosted control, and lighter-weight tools like ConfigCat; LaunchDarkly differentiates itself through the maturity and scale of its streaming flag-delivery infrastructure, its enterprise compliance certifications, and its early, dedicated move into governing AI-agent behavior as a distinct product line rather than an add-on feature.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd6a26ca4-38a0-43e3-8120-1f2c0a119cc1';

