-- ── Lavender ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lavender is an AI email coaching assistant that scores, rewrites and optimizes sales emails in real time inside Gmail, Outlook and CRMs.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan from about $27-29/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$51-100 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lavender Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lavender review 2026: AI email coaching features, pricing plans, and how this sales email assistant compares to Yesware, Outreach and Salesloft.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lavender is an AI-powered email coaching platform for sales teams, founded in 2020 and headquartered in New York, built to give sellers real-time, data-driven feedback on cold emails and outreach messages the way a sales coach would review a call. Lavender created what its founders describe as the 'email intelligence' category and raised a total of about $13.2 million in venture funding, starting with a $2.2 million seed round led by Signia Venture Partners with participation from CapitalX and Position Ventures, followed roughly a year later by an $11 million Series A led by Norwest Venture Partners with continued participation from Signia; the company has grown to roughly 77 employees and counts customers including Clari, Lucidworks, Segment, Sendoso, Sharebite and Twilio. Architecturally, Lavender is delivered primarily as a browser extension and email-client plugin that overlays directly on Gmail, Outlook, and major sales-engagement and CRM platforms such as Salesloft, Outreach, HubSpot and Salesforce; as a rep drafts an email, Lavender's AI analyzes the copy in real time and returns an overall email score along with specific, line-by-line suggestions covering readability, tone, length, personalization, spelling and grammar, and spam-trigger phrases that could hurt deliverability, functioning less like a generic grammar checker and more like a sales-specific writing coach trained on patterns from millions of analyzed emails. Beyond live scoring, Lavender includes AI-generated email and subject-line rewrites, automated prospect and company research pulled into the compose window so reps do not have to tab out to LinkedIn or a company website, team and manager-facing analytics dashboards that show coaching trends and email-quality benchmarks across a sales org, and integrations that let managers identify which reps and message patterns are driving replies versus getting ignored. Pricing follows a freemium structure: the free plan is capped at a small number of monthly email analyses and personalizations (around five of each) alongside basic scoring features, intended as a trial-like entry point rather than a fully usable free tier for active sellers; the Starter individual plan runs roughly $27 to $29 per month and unlocks full, unlimited access to the core AI writer, real-time scoring, and the Chrome/email extension; Individual Pro runs roughly $45 to $49 per month and adds third-party CRM and sales-engagement integrations plus priority support; and a Team plan, priced around $89 per user per month, adds team-wide coaching analytics, manager dashboards and org-level reporting, with roughly 20 percent savings typically available for annual billing and a 7-day free trial offered on paid tiers. Lavender's target audience is business-to-business sales development representatives, account executives, and sales leaders at technology and SaaS companies who send high volumes of cold or semi-personalized outbound email and want to systematically improve reply rates without hiring a dedicated sales-enablement coach for every rep; it is also used by revenue-operations and sales-enablement teams that want visibility into which messaging patterns correlate with pipeline generation across an entire sales floor. Its competitive landscape includes Yesware, a longer-established sales engagement and email-tracking platform focused more on send/open tracking and campaign automation than AI coaching; Outreach and Salesloft, comprehensive sales-engagement platforms that manage entire multi-channel outbound sequences and are typically deployed by larger sales organizations, of which Lavender is often used as a complementary coaching layer rather than a replacement; and Gong, a revenue-intelligence platform that analyzes recorded sales calls rather than written email, overlapping with Lavender only at the margins of the broader 'sales AI coaching' category. Lavender differentiates itself by focusing narrowly and deeply on the moment of email composition itself, providing instant, actionable, line-level feedback inside the compose window rather than after-the-fact campaign analytics, which is why it is frequently adopted alongside rather than instead of full sales-engagement platforms like Outreach or Salesloft.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76d57e8b-f525-42a1-a189-fcf48f10fecf';

