INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Multilingual grammar checking$q$, $q$Checks grammar, spelling and punctuation across 30-plus languages and regional variants, most maintained by volunteer native-speaker linguists.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$AI-powered paraphrasing$q$, $q$Premium unlocks unlimited AI sentence rewriting to improve clarity, tone and style; the free plan allows a few paraphrases per day.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Browser and desktop integration$q$, $q$Available as add-ons for Chrome, Firefox, Edge and Safari, plus native desktop apps for Windows, macOS and Linux.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Custom style guide$q$, $q$Premium and Teams users can define preferred terminology and phrasing rules enforced consistently across documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Developer API and self-hosting$q$, $q$A REST API and self-hostable server package let businesses embed checking into their own products or run the engine on-premise for data privacy.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Team dictionary and management$q$, $q$Teams plans add a shared dictionary for technical terms, email-based member management, and centralized billing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Document editor integrations$q$, $q$Works natively inside Google Docs, Microsoft Word, Outlook, and OpenOffice/LibreOffice.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Open-source core engine$q$, $q$The underlying rule-based engine is open source on GitHub, letting the community contribute rules and new language support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Genuinely usable free tier compared to most grammar-checker competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Strongest multilingual support in the category, covering 30-plus languages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Open-source core allows self-hosting for data-sensitive organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Two-year plan pricing is significantly cheaper than Grammarly's comparable tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Works across a wide range of browsers, desktop apps and document editors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$AI writing/rewriting features are less extensive than Grammarly's full suite$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Interface and suggestions can feel less polished than newer AI-first competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Monthly billing is comparatively expensive versus the discounted annual/2-year plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Some advanced style checks are limited to fewer languages than English$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Team pricing is not transparently listed and may require inquiry for larger seats$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Is LanguageTool free to use?$q$, $q$Yes, LanguageTool offers a free Basic plan with core grammar and spelling checks, a 2,000-character limit per text, and three free paraphrases per day.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$How many languages does LanguageTool support?$q$, $q$LanguageTool supports more than 30 languages and regional variants, including English, German, French, Spanish, Portuguese, Dutch, Italian, Polish, Russian, Ukrainian, Chinese and Japanese.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Is LanguageTool open source?$q$, $q$Yes, the core rule-based checking engine is open source and available on GitHub, and it can be self-hosted by organizations that need on-premise deployment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$How does LanguageTool compare to Grammarly?$q$, $q$LanguageTool offers broader multilingual support and a self-hosting option, while Grammarly has a larger AI-writing feature set and is more English-focused with wider brand recognition.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$What is included in LanguageTool Premium?$q$, $q$Premium adds over 20,000 additional grammar and style checks, a 150,000-character limit per text, unlimited AI paraphrasing, a custom style guide, and access to all supported languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Does LanguageTool offer a Teams plan?$q$, $q$Yes, Teams plans support 2 to 20-plus members with all Premium features plus a shared Team Style Guide, Team Dictionary, and centralized billing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Multilingual academic and professional writing$q$, $q$Students and professionals writing in a non-native language use LanguageTool to catch grammar and style errors across dozens of languages that English-only checkers miss.$q$, $q$Students and non-native English writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Privacy-conscious enterprise proofreading$q$, $q$Organizations with strict data-residency requirements self-host the open-source engine or use the API to embed checking into internal tools without sending text to third-party clouds.$q$, $q$Enterprise IT and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Team-wide style consistency$q$, $q$Marketing and content teams use the Teams plan's shared style guide and dictionary to keep terminology and tone consistent across writers.$q$, $q$Marketing and content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Basic (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2,000 character limit per text","3 free paraphrases per day","Core grammar and spelling checks","Browser add-on access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Premium Monthly$q$, $q$$24.90/month$q$, $q$Monthly$q$, NULL, $q$["20,000+ additional checks","150,000 character limit","Unlimited AI paraphrasing","All 30+ languages","Custom style guide"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Premium Annual$q$, $q$$7/month (billed annually)$q$, $q$Annual$q$, NULL, $q$["All Premium features","Lower effective monthly cost","Bestseller plan"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Premium 2-Year$q$, $q$$4.17/month (billed every 2 years)$q$, $q$Biennial$q$, NULL, $q$["All Premium features","Lowest effective monthly cost"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$Teams$q$, $q$Custom per-seat pricing$q$, $q$Varies$q$, NULL, $q$["All Premium features","Team Style Guide","Team Dictionary","Centralized billing for 2-20+ members"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LanguageTool is a grammar, spelling and style checker that started as an open-source research project in 2003 and has since grown into a commercial product used by writers, students, businesses and developers who need multilingual proofreading beyond what English-only tools provide.$q$, $q$The platform blends thousands of hand-written grammar rules with machine-learning and generative-AI models, giving it both a reliable rule-based foundation and modern AI-powered rewriting and paraphrasing capabilities, all while keeping an open-source core engine publicly available.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LanguageTool checks grammar, spelling, punctuation and style across more than 30 languages and regional variants, and ships as browser add-ons, desktop apps, mobile keyboards, document-editor integrations, and a developer API.$q$, $q$Premium unlocks over 20,000 additional style and grammar checks, a much higher character limit per document, unlimited AI paraphrasing, and a custom style guide for enforcing consistent terminology across a team or organization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LanguageTool offers a genuinely usable free Basic plan alongside an Individual Premium subscription billed monthly, quarterly, annually or every two years, with per-month cost dropping sharply the longer the commitment.$q$, $q$A Teams plan adds centralized billing, a shared style guide and dictionary for organizations with 2 to 20-plus members, while larger companies can opt for Business/Enterprise deployment including self-hosting options.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
