INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('917d6a1d-804c-4ce5-b0e0-d9db22f252c6', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Zero-knowledge encrypted vault$q$, $q$Passwords are encrypted and decrypted locally with a master password LastPass never has access to.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Cross-device autofill$q$, $q$Browser extensions and mobile apps autofill saved logins across Chrome, Firefox, Edge, Safari, iOS and Android.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Dark web monitoring$q$, $q$Alerts users when their email or credentials appear in known data breaches.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Security dashboard$q$, $q$Scores password strength and flags reused or weak passwords across the vault.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Secure sharing$q$, $q$Share individual logins or shared folders with family members or teammates without exposing the plaintext password.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Admin console and policies$q$, $q$Business tiers include a centralized console with configurable security policies, SSO and directory sync.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Built-in authenticator$q$, $q$Generates time-based one-time passcodes (TOTP) for two-factor authentication without a separate app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$SaaS monitoring$q$, $q$Business Max detects unsanctioned or risky SaaS application usage across an organization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Free plan includes unlimited password storage$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Long-established brand with broad platform and browser support$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Deep business admin console and security policy controls$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Family plan is competitively priced for up to 6 users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$30-day free trial on Premium and Families plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Past security breaches (notably 2022) remain a lasting reputational concern$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Free plan restricts users to a single device type$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Business Max pricing is higher than some competitors' top tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Interface is viewed by some reviewers as less polished than 1Password$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$All paid plans require annual billing to get advertised per-month pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Is LastPass free to use?$q$, $q$Yes, LastPass offers a free plan with unlimited password storage, though it restricts access to a single device type.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$How much does LastPass Premium cost?$q$, $q$LastPass Premium costs around $3/month when billed annually, with a 30-day free trial available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Is LastPass still owned by GoTo?$q$, $q$No, LastPass was spun off from GoTo (formerly LogMeIn) into an independent, standalone company in 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$What happened in the LastPass security breaches?$q$, $q$In 2022, attackers stole encrypted customer vault backups from a cloud storage environment; LastPass subsequently overhauled its security architecture and leadership.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$What is the difference between LastPass Business and Business Max?$q$, $q$Business Max adds SaaS Monitoring, SaaS Protect, unlimited SSO app integrations and advanced multi-factor authentication on top of the standard Business plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$How many users can share a LastPass Families plan?$q$, $q$LastPass Families supports up to six individual encrypted vaults under one family plan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Personal password management$q$, $q$Individuals use LastPass to generate, store and autofill unique passwords across all their online accounts.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Family credential sharing$q$, $q$Households use the Families plan to give each member their own vault while sharing select logins like streaming or utility accounts.$q$, $q$Families and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Enterprise credential governance$q$, $q$IT and security teams use Business/Business Max to enforce password policies, SSO and SaaS usage monitoring across employees.$q$, $q$IT and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited password storage","Limited to 1 device type","Autofill and password generator","Dark web monitoring","Basic password sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Premium$q$, $q$$3/month$q$, $q$Annual$q$, NULL, $q$["Access on all devices","Unlimited passwords","Security dashboard","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Families$q$, $q$$4/month$q$, $q$Annual$q$, NULL, $q$["6 individual vaults","Shared folders","Family manager dashboard","30-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Teams$q$, $q$$4/user/month$q$, $q$Annual$q$, NULL, $q$["Up to 50 users","Admin console","25 security policies","14-day free trial"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Business$q$, $q$$7/user/month$q$, $q$Annual$q$, NULL, $q$["Unlimited users","100+ security policies","LastPass Families included","Advanced reporting"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$Business Max$q$, $q$$9/user/month$q$, $q$Annual$q$, NULL, $q$["Unlimited SSO apps","SaaS Monitoring and Protect","Advanced MFA","Unlimited users"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LastPass is one of the longest-running consumer and business password managers, founded in 2008 and now operating as an independent company after nearly a decade under GoTo/LogMeIn ownership and a 2024 spin-off.$q$, $q$The platform uses zero-knowledge encryption so vault data can only be decrypted locally with a user's master password, and it syncs encrypted vaults across browsers, desktop apps and mobile devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include password storage and generation, autofill, secure notes, dark web monitoring, and a security dashboard that flags weak or reused passwords.$q$, $q$Business tiers add a centralized admin console, configurable security policies, SSO and directory integration, SCIM provisioning, and SaaS application monitoring for IT and security teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LastPass offers a free single-device-type plan alongside paid Premium and Families plans for individuals and households, all billed annually with free trial periods.$q$, $q$Three business tiers - Teams, Business and Business Max - scale per-user pricing with increasing security policy controls, SSO capabilities and SaaS monitoring features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('442e0b90-c0fa-4f16-8c2e-e77ca49e1ccf', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
