INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Visual builder with custom JavaScript$q$, $q$Every node can run full JavaScript with NPM packages, combining no-code simplicity with developer-grade flexibility.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$1,200+ app integrations$q$, $q$Connects to over 1,200 named apps and more than 5,500 total integrations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Native AI model access$q$, $q$Built-in access to GPT, Claude, Gemini and 1,200+ AI models directly inside workflow nodes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$AI agent builder$q$, $q$Drag-and-drop builder for constructing multi-step autonomous AI agents and multi-agent orchestration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Headless browser automation$q$, $q$Built-in headless browser enables web scraping and browser-based automation tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Built-in database and RAG storage$q$, $q$NoSQL databases and retrieval-augmented generation storage let workflows store state and ground AI responses in company data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$CPU-second based pricing$q$, $q$Bills by actual execution time rather than per-operation or per-task, aiming for more predictable costs at scale.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Enterprise security$q$, $q$SOC 2 alignment, SSO, role-based access control and GDPR alignment for larger organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Execution-time pricing can be significantly cheaper than per-task competitors at scale$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Full JavaScript and NPM support inside nodes for advanced logic$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Core platform features are not restricted to higher-priced tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Built-in AI models, agent builder and RAG remove need for separate AI tooling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Generous free tier with 10,000 CPU-seconds per month$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Usage-based pricing can be harder to predict upfront than flat-rate plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Newer platform (founded 2022) with a smaller community than Zapier or Make$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Separate PnP token system adds a second cost dimension to track$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$No disclosed venture funding may raise questions about long-term scale for enterprise buyers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Company headquarters and size are not publicly disclosed$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Is Latenode free to use?$q$, $q$Yes, Latenode offers a free plan with 10,000 CPU-seconds per month, five active workflows, and access to the full visual builder and integrations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$How does Latenode's pricing differ from Zapier or Make?$q$, $q$Latenode bills by actual CPU execution seconds rather than per operation or task, so a workflow's cost depends on how long it runs rather than how many steps it contains.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Can I write custom code in Latenode?$q$, $q$Yes, every node supports full JavaScript with NPM package imports, allowing custom logic, loops and conditional branching beyond standard no-code connectors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Does Latenode support AI agents?$q$, $q$Yes, it includes a drag-and-drop AI agent builder plus native access to GPT, Claude, Gemini and other models directly inside workflow nodes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$What are Latenode's PnP tokens?$q$, $q$Plug-n-Play tokens, priced at $1 each, pay for premium provider nodes such as certain AI models, file converters, and authenticated connections to platforms like Telegram or WhatsApp.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Who are Latenode's main competitors?$q$, $q$Latenode competes primarily with Zapier, Make and n8n in the workflow automation space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Cost-sensitive high-volume automation$q$, $q$Teams running large volumes of automated workflows use Latenode's execution-time pricing to avoid the per-task costs that make Zapier expensive at scale.$q$, $q$Operations and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Custom logic and API integration$q$, $q$Developers use built-in JavaScript support to add loops, conditionals and bespoke API calls that standard no-code connectors cannot handle.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$AI agent and RAG workflows$q$, $q$AI-forward teams build multi-step agents that call LLMs, retrieve data via RAG, and take automated actions across connected apps.$q$, $q$AI and automation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["10,000 CPU-seconds/month included","5 active workflows","1 execution worker","3-minute execution time limit","Full visual builder and all app integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Pay as You Go$q$, $q$$0 base + usage-based (from $0.00005-$0.00012/CPU-second)$q$, $q$Monthly, usage-based$q$, NULL, $q$["Unlimited workflows and executions","5 execution workers included","10-minute execution time limit","30-day execution history","Declining tiered CPU-second rate"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Custom volume and compliance terms","SOC 2, SSO and RBAC","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Latenode is a workflow automation platform, founded in 2022, that pairs a visual drag-and-drop builder with full custom JavaScript support inside any node, positioning itself between simple no-code tools and developer-only platforms like n8n.$q$, $q$The platform emphasizes predictable, execution-time-based pricing instead of per-task billing, along with native AI model access and agent-building tools built directly into the workflow canvas.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Latenode connects to 1,200+ apps and 5,500+ total integrations, and includes a headless browser for web scraping, built-in NoSQL databases, global variables, and RAG storage for grounding AI responses in company data.$q$, $q$An AI Agent node and drag-and-drop agent builder let teams construct multi-step autonomous workflows using GPT, Claude, Gemini and other models natively, without separate API setup.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan includes 10,000 CPU-seconds per month with full access to the core platform, while the Pay-as-you-Go plan removes workflow limits and bills only for actual execution seconds on a declining tiered rate.$q$, $q$Optional add-ons cover extra execution workers, longer runtimes and larger file sizes, while a separate token system pays for premium provider nodes like certain AI models and messaging-platform connections.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
