INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f977f684-1fe1-4506-a3eb-4159d62fd97f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Visual content calendar$q$, $q$Drag-and-drop scheduling calendar for planning and auto-publishing posts across connected social profiles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Linkin.bio$q$, $q$Turns an Instagram grid into a clickable, shoppable landing page linking each post to a destination URL.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Multi-platform publishing$q$, $q$Schedules content to Instagram, Facebook, TikTok, Threads, YouTube, Pinterest, LinkedIn and Snapchat.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$AI content generation$q$, $q$AI credits let users generate captions, hashtags and content ideas directly inside the scheduling calendar.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Analytics and benchmarking$q$, $q$Reports engagement and best-time-to-post recommendations, with competitive benchmarking on the Scale plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Team collaboration$q$, $q$Multi-user access and collaboration tools for agencies and teams managing multiple brand accounts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Influencer and creator campaigns$q$, $q$Following the Mavrck merger, Later supports influencer discovery and creator campaign management alongside organic scheduling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Mobile apps$q$, $q$Native iOS and Android apps let users manage scheduling and review content on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Strong visual-first design well suited to Instagram and TikTok content$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Linkin.bio adds shoppable-link functionality not bundled by all competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Post-Mavrck merger adds native influencer marketing capabilities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$AI credits included on every paid plan for content generation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Tiered social-set structure scales cleanly for agencies managing multiple clients$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$No prominently advertised free plan on the current pricing page$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Analytics depth is generally viewed as less comprehensive than Sprout Social$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Add-on costs for extra social sets and users can add up for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Starter plan's single social set may be limiting for multi-platform brands$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Pricing has shifted over time, creating some confusion around current free-tier availability$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Does Later have a free plan?$q$, $q$Later has historically offered a limited free plan for creators posting infrequently, though it is not prominently featured on the current pricing page, which instead emphasizes paid plans with a trial period.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$What is a 'social set' in Later's pricing?$q$, $q$A social set is a bundle of up to eight connected social media profiles; plans scale by how many social sets, users, and posts per profile are included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$What social platforms does Later support?$q$, $q$Later supports Instagram, Facebook, TikTok, Threads, YouTube, Pinterest, LinkedIn and Snapchat.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$What is Linkin.bio?$q$, $q$Linkin.bio is Later's tool that turns an Instagram profile's single bio link into a clickable, shoppable landing page tied to individual posts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Is Later good for agencies?$q$, $q$Yes, higher tiers like Growth and Scale include multiple users, multiple social sets, and collaboration tools suited to agencies managing several client accounts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$How does Later differ from Buffer or Hootsuite?$q$, $q$Later has a more visual, Instagram/TikTok-first design and includes Linkin.bio and influencer marketing tools, while Hootsuite and Sprout Social generally offer broader analytics and enterprise features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Visual-first Instagram and TikTok scheduling$q$, $q$Creators and brands use Later's visual calendar and Linkin.bio to plan grid layouts and drive traffic from Instagram bios.$q$, $q$Creators and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Multi-client agency management$q$, $q$Social media agencies use multiple social sets and collaboration tools to manage scheduling across several client brands from one account.$q$, $q$Marketing and social media agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Influencer and creator campaigns$q$, $q$Brands use Later's Mavrck-derived tools to discover creators, run influencer campaigns, and manage content alongside organic scheduling.$q$, $q$Brand marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Starter$q$, $q$$18.75/month$q$, $q$Annual$q$, NULL, $q$["1 social set (8 profiles)","1 user","30 posts per profile/month","5 AI credits/month","Up to 3 months of analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Growth$q$, $q$$37.50/month$q$, $q$Annual$q$, NULL, $q$["2 social sets (16 profiles)","2 users","180 posts per profile/month","50 AI credits/month","Up to 1 year of analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$Scale$q$, $q$$82.50/month$q$, $q$Annual$q$, NULL, $q$["6 social sets (48 profiles)","4 users","Unlimited posts","100 AI credits/month","Competitive benchmarking, up to 2 years of analytics"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Later began in 2013 as Latergramme, one of the earliest Instagram scheduling tools, and has since grown into a full social media marketing platform covering Instagram, TikTok, Facebook, Pinterest, LinkedIn, YouTube and Snapchat.$q$, $q$Following its 2024 merger with influencer-marketing platform Mavrck, Later now spans both organic content scheduling and influencer/creator campaign management under one unified platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Later's visual content calendar, bulk scheduling and Linkin.bio shoppable-link tool remain central to its Instagram-first heritage, alongside analytics, best-time-to-post recommendations and competitive benchmarking on higher tiers.$q$, $q$AI credits built into every plan let users generate captions and content ideas directly inside the calendar, while collaboration tools support teams managing multiple brands or client accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Later's three main tiers - Starter, Growth and Scale - scale by number of connected social profiles ('social sets'), team seats, monthly post volume, AI credits and analytics history, billed monthly or at a discounted annual rate.$q$, $q$Add-ons let teams purchase extra social sets, users and AI credits beyond a plan's included allotment as their social presence grows.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('34b4f794-ce37-4598-b6e9-fe9e9269a4c8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Performance reviews and calibration$q$, $q$Structured review cycles, succession planning, promotion and PIP workflows, and calibration sessions for managers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Goals and OKRs$q$, $q$Cascading company-to-individual goal trees with progress tracking and integrations like Salesforce and Jira.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Engagement surveys$q$, $q$Pulse, onboarding and exit surveys with eNPS tracking and AI-generated trend analysis.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Lattice AI Agent$q$, $q$Built into 1:1s and available at no extra cost, generating meeting notes, coaching insights, review drafts and analytics charts from plain-language queries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$1:1s and feedback tools$q$, $q$Shared meeting notes, weekly updates, peer feedback and Q&A boards underpin every module.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Compensation management (add-on)$q$, $q$Comp bands, benchmarking data, cycle management and multi-step approval workflows for pay decisions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Career growth tools (add-on)$q$, $q$Competency frameworks, individual development plans and career-track mapping.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Analytics and integrations$q$, $q$Cross-module analytics engine plus integrations with common HR, calendar and productivity tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Modular pricing lets companies buy only the products they need$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$AI Agent is included free across the platform rather than gated to higher tiers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Strong brand recognition and long track record in continuous performance management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Foundations bundle offers a cost-efficient combination of the two most-used modules$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Dedicated human support included on every contract$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$No self-serve free trial; requires a sales demo to see pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$$4,000 minimum annual spend may be high for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$USD-only billing can complicate international purchasing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Sunsetting HRIS and payroll narrows Lattice's role to performance-adjacent HR needs only$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Per-seat, per-module pricing can become expensive as companies add multiple modules$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Does Lattice offer a free trial?$q$, $q$No, Lattice does not offer a self-serve free trial; prospective customers go through a sales-assisted demo to get pricing tailored to their team.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$What is Lattice's Foundations plan?$q$, $q$Foundations bundles the Performance and Goals and OKRs modules together at a discounted combined price and is Lattice's most popular pre-configured package.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Is Lattice still offering HRIS and payroll?$q$, $q$No, Lattice announced in 2025 that it would sunset its HRIS and payroll products by mid-2026 to refocus on performance management, goals and engagement.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$How is Lattice priced?$q$, $q$Lattice is priced per seat per month, billed annually, with each module (Performance, Goals and OKRs, Engagement) purchasable individually or combined, plus optional Compensation and Grow add-ons.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$What is the Lattice AI Agent?$q$, $q$The Lattice AI Agent is built into 1:1 meetings and other workflows, generating notes, coaching suggestions, review drafts and plain-language analytics charts, included free for all customers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Who are Lattice's main competitors?$q$, $q$Lattice's main competitors include Culture Amp, 15Five, Leapsome and Betterworks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Continuous performance management$q$, $q$HR teams replace annual review cycles with continuous 1:1s, feedback and structured performance review cycles using Lattice's Performance module.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Company-wide OKR tracking$q$, $q$Leadership and managers cascade company goals down to team and individual OKRs with progress tracking integrated into existing tools.$q$, $q$Leadership and department managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Employee engagement measurement$q$, $q$People teams run pulse, onboarding and exit surveys to track eNPS and engagement trends over time using AI-generated analysis.$q$, $q$People operations and HR leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Engagement$q$, $q$$4/seat/month$q$, $q$Annual$q$, NULL, $q$["Pulse surveys","Onboarding and exit surveys","eNPS tracking","AI analysis and trends"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Goals and OKRs$q$, $q$$8/seat/month$q$, $q$Annual$q$, NULL, $q$["Cascading goals","Progress updates","Salesforce and Jira integration","Configurable setup"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Performance$q$, $q$$10/seat/month$q$, $q$Annual$q$, NULL, $q$["Performance reviews","Succession planning","Promotions and PIPs","Calibration and talent reviews"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Foundations (Most Popular)$q$, $q$$13/seat/month$q$, $q$Annual$q$, NULL, $q$["Performance module","Goals and OKRs module","All base features included"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Compensation (Add-on)$q$, $q$+$6/seat/month$q$, $q$Annual$q$, NULL, $q$["Global benchmarks","Comp bands","Cycle management","Multi-chain approvals"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$Grow (Add-on)$q$, $q$+$4/seat/month$q$, $q$Annual$q$, NULL, $q$["Competencies","Individual development plans","Career tracks","AI-powered growth areas"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lattice is a modular people-management platform, founded in 2015, built around continuous performance reviews, goal-setting and employee engagement rather than a once-a-year review cycle.$q$, $q$After expanding into full HR-information-system and payroll products, Lattice announced in 2025 it would sunset those offerings to refocus specifically on its original performance management strengths.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core modules cover Performance reviews and calibration, Goals and OKRs, and Engagement surveys, all connected through shared 1:1 notes, weekly check-ins and feedback tools.$q$, $q$An AI Agent, included free for all customers, auto-generates meeting notes, coaching suggestions, review drafts and plain-language analytics charts across the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lattice prices each module separately on a per-seat, annually billed basis, with a $4,000 minimum annual contract, and modules can be combined or purchased individually.$q$, $q$The Foundations bundle, combining Performance and Goals and OKRs, is the most popular pre-configured package, with Compensation and Grow available as additional add-on modules.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('347340e4-2920-47db-a757-9978b6eb89a7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Feature flag management$q$, $q$Toggle features, roll out to targeted user segments, and instantly roll back without a code redeploy.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$A/B testing and experimentation$q$, $q$Run controlled experiments tied directly to feature flags to measure impact before full rollout.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$AgentControl for AI features$q$, $q$Governs AI agent and LLM-powered feature behavior in production, tracking AI runs and enabling kill-switches and guardrails.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Broad SDK support$q$, $q$SDKs available for roughly 30 languages and frameworks for both server-side and client-side flag evaluation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Session replay and observability$q$, $q$Session replay and error tracking help teams understand user impact of flagged releases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Release automation and approvals$q$, $q$Enterprise tiers add scheduling, approval workflows and audit logging for regulated release processes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Automatic rollback (Guardian)$q$, $q$Guardian tier monitors guardrail metrics and can automatically pause or roll back risky releases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Single sign-on and SCIM$q$, $q$Foundation and above add SSO, with Enterprise/Guardian adding SAML/SCIM for identity governance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Generous free Developer plan with unlimited seats and flags$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Mature, high-scale streaming infrastructure for flag delivery$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Dedicated AgentControl product for governing AI/LLM features in production$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Strong enterprise compliance and audit capabilities$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Broad SDK language and framework coverage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Foundation and above pricing can become complex with multiple usage dimensions (service connections, MAUs, AI runs)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Enterprise and Guardian tiers require custom quotes rather than transparent pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Advanced release automation and guardrails are reserved for the highest-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Learning curve for teams new to feature-flag-driven development practices$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$AgentControl is a newer product line with a shorter track record than CodeControl$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Is LaunchDarkly free to use?$q$, $q$Yes, the Developer plan is free with unlimited seats, unlimited feature flags, 10 million logs and traces, and 5,000 AI runs per month, with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$What is AgentControl?$q$, $q$AgentControl is LaunchDarkly's product for governing AI agent and LLM-powered feature behavior in production, tracking AI runs and enabling guardrails, kill-switches and staged rollouts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$How is LaunchDarkly's Foundation plan priced?$q$, $q$Foundation is billed yearly at around $10/month per service connection plus roughly $8.33/month per 1,000 client-side monthly active users, with AI run overages billed separately.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$What is the difference between Enterprise and Guardian plans?$q$, $q$Guardian includes everything in Enterprise plus automated release monitoring, guardrail metrics, proactive failure notifications and automatic pause-or-rollback of risky releases.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Who founded LaunchDarkly?$q$, $q$LaunchDarkly was founded in 2014 by Edith Harbaugh and John Kodumal in Oakland, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Who are LaunchDarkly's main competitors?$q$, $q$LaunchDarkly's main competitors include Split, Optimizely, and open-source alternatives like Flagsmith and Unleash.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Safe, incremental feature rollouts$q$, $q$Engineering teams use feature flags to release code to production and gradually roll out to user segments without redeploying.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$A/B testing and experimentation$q$, $q$Product teams run controlled experiments tied to feature flags to measure the impact of new features before full release.$q$, $q$Product managers and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Governing AI agent behavior in production$q$, $q$AI/ML platform teams use AgentControl to add guardrails, kill-switches and staged rollouts for LLM-powered features.$q$, $q$AI and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Developer$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited seats","Unlimited feature flags","10M logs and traces","5,000 AI runs/month","14-day data retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Foundation$q$, $q$From $10/month per service connection + $8.33/month per 1K client-side MAU$q$, $q$Annual$q$, NULL, $q$["User, account and device targeting","Unlimited projects","Single sign-on","30-day data retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Advanced targeting","Release automation and workflows","SAML/SCIM","100+ day data retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$Guardian$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Release monitoring","Guardrail metrics","Automatic pause or rollback","Advanced observability"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LaunchDarkly, founded in 2014 by Edith Harbaugh and John Kodumal, pioneered feature flags as a hosted service, letting engineering teams toggle features, roll out to segments, and roll back instantly without redeploying code.$q$, $q$The platform has since expanded from CodeControl (traditional feature flag management) into AgentControl, a companion product for governing AI agent and LLM behavior in production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include unlimited feature flags, user/account/device targeting, A/B testing and experimentation, session replay, and SDKs for roughly 30 languages and frameworks.$q$, $q$AgentControl extends the same runtime-control model to AI features, tracking 'AI runs' and enabling kill-switches, guardrails and staged rollouts for LLM-powered functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$A free Developer plan offers unlimited seats and generous flag, log and AI-run limits with no credit card required, making LaunchDarkly accessible to small teams and individual developers.$q$, $q$Paid tiers - Foundation, Enterprise and Guardian - add SSO, release automation, advanced targeting, compliance certifications and automated release monitoring as organizations scale.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d6a26ca4-38a0-43e3-8120-1f2c0a119cc1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
