INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Real-time email scoring$q$, $q$Analyzes email drafts as they are written, returning an overall score and line-by-line coaching feedback.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$AI rewrite suggestions$q$, $q$Generates improved email and subject-line rewrites to boost clarity, tone and reply rates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Spam and deliverability check$q$, $q$Flags spelling errors, grammar issues and spam-trigger phrases that could hurt email deliverability.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Prospect and company research$q$, $q$Pulls relevant prospect and company information directly into the compose window.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$CRM and sales-engagement integrations$q$, $q$Integrates with Gmail, Outlook, Salesforce, HubSpot, Salesloft and Outreach.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Team coaching analytics$q$, $q$Manager dashboards show email-quality trends and coaching benchmarks across a sales team.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Chrome and email extension$q$, $q$Delivered as a lightweight browser and email-client overlay rather than a separate application to switch to.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Real-time, line-level feedback inside the compose window rather than after-the-fact analytics$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Complements rather than replaces existing sales-engagement platforms like Outreach or Salesloft$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Manager dashboards give visibility into which messaging patterns drive replies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Strong customer base among recognizable B2B SaaS companies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$7-day free trial available on paid plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Free plan is very limited (around 5 analyses/personalizations per month)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Team plan at roughly $89/user/month is priced at a premium versus some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Primarily focused on email; does not cover calls or other outbound channels directly$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Best value requires pairing with a separate CRM or sales-engagement platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Pricing not fully transparent across all sources, with some variation reported$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Is Lavender free to use?$q$, $q$Lavender offers a limited free plan with around five email analyses and five personalizations per month; unlimited access requires a paid Starter, Pro or Team plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$What does Lavender's email score measure?$q$, $q$Lavender scores emails on readability, tone, length, personalization, spelling and grammar, and spam-trigger language, providing line-by-line feedback to improve reply rates.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Does Lavender integrate with my CRM?$q$, $q$Yes, Lavender integrates with Gmail, Outlook, and sales tools like Salesforce, HubSpot, Salesloft and Outreach, with deeper integrations available on the Pro and Team plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$How much does Lavender cost for teams?$q$, $q$Lavender's Team plan is priced at around $89 per user per month and adds manager dashboards and org-wide coaching analytics.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Who uses Lavender?$q$, $q$Lavender is used primarily by B2B sales development reps, account executives and sales leaders who send high volumes of outbound email and want to improve reply rates.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$How is Lavender different from Outreach or Salesloft?$q$, $q$Outreach and Salesloft manage entire multi-channel outbound sequences, while Lavender focuses specifically on coaching the quality of individual email drafts, and is often used alongside those platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Cold outbound email coaching$q$, $q$SDRs use Lavender's real-time scoring and rewrite suggestions to improve cold email quality and reply rates before hitting send.$q$, $q$Sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Sales team coaching at scale$q$, $q$Sales managers use Team plan analytics dashboards to identify which reps and messaging patterns are underperforming and need coaching.$q$, $q$Sales managers and sales enablement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Faster prospect research during outreach$q$, $q$Account executives use built-in prospect and company research to personalize emails without leaving their inbox.$q$, $q$Account executives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["~5 email analyses/month","~5 personalizations/month","Basic scoring features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Starter$q$, $q$$27-29/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited email analyses","Real-time scoring","Chrome and email extension","Core AI writer"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Individual Pro$q$, $q$$45-49/month$q$, $q$Monthly or annual$q$, NULL, $q$["All Starter features","Third-party CRM integrations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$Team$q$, $q$$89/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Team coaching analytics","Manager dashboards","Org-level reporting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lavender, founded in 2020, is an AI email coaching platform built specifically for B2B sales teams, overlaying Gmail and Outlook with real-time scoring and rewrite suggestions as reps draft outbound emails.$q$, $q$The company created what it calls the 'email intelligence' category, raising $13.2 million in venture funding and counting customers such as Clari, Segment, Twilio and Sendoso.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lavender's core feature is a real-time email score with line-by-line feedback on readability, tone, personalization, spelling, grammar and spam-trigger language as a rep types.$q$, $q$The platform also automates prospect and company research inside the compose window and provides manager-facing analytics dashboards showing coaching trends across a sales team.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$A limited free plan offers around five email analyses and personalizations per month, while Starter and Individual Pro plans unlock unlimited scoring, AI rewrites and CRM integrations for individual sellers.$q$, $q$The Team plan adds manager dashboards and org-wide coaching analytics at a per-user price, with roughly 20 percent savings on annual billing and a 7-day free trial on paid tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d57e8b-f525-42a1-a189-fcf48f10fecf', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$iPad-native POS$q$, $q$Runs on Apple iPads as the primary terminal, paired with a cloud-synced back office for menu, inventory and sales data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Kitchen display system$q$, $q$Routes order tickets directly to kitchen screens instead of paper printers, reducing errors and speeding up service.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Offline mode$q$, $q$Terminals continue taking orders during internet outages and sync automatically once connectivity is restored.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Integrated payment processing$q$, $q$Built-in payment processing handles card and contactless transactions directly through the POS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Online ordering and delivery integrations$q$, $q$Connects in-house online ordering with third-party delivery platforms alongside in-store orders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Employee scheduling and payroll$q$, $q$Manages staff schedules and payroll directly within the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Marty AI assistant$q$, $q$AI assistant that surfaces sales insights and automates back-office reporting from natural-language queries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Lavu Capital financing$q$, $q$Offers restaurant operators working-capital advances powered by fintech partner Parafin, based on processing history.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$One of the original iPad-native restaurant POS platforms with a mature feature set$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Offline mode keeps service running during internet outages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Bundles payroll and scheduling alongside core POS functionality$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Lavu Capital provides built-in access to working-capital financing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Generally positioned as more affordable than Toast for independent restaurants$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Pricing is not fully transparent online and typically requires a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Smaller market share and integration ecosystem compared to Toast and Square$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$iPad dependency ties hardware choice to Apple's ecosystem and pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Reported starting prices vary across third-party sources, adding some uncertainty$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Less brand recognition among large multi-location enterprise chains$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$How much does Lavu cost?$q$, $q$Lavu's pricing is largely quote-based, with third-party trackers reporting entry packages starting around $59-69 per month per terminal, scaling up based on terminals, users and features selected.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Does Lavu work offline?$q$, $q$Yes, Lavu supports an offline mode that lets terminals keep taking orders during internet outages, syncing data once connectivity is restored.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$What is Marty AI?$q$, $q$Marty AI is Lavu's built-in AI assistant that surfaces sales insights and automates parts of back-office reporting from natural-language queries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$What is Lavu Capital?$q$, $q$Lavu Capital, launched in 2022 and powered by fintech partner Parafin, offers restaurant operators working-capital financing based on their payment processing history.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$What hardware does Lavu run on?$q$, $q$Lavu runs primarily on Apple iPads as the point-of-sale terminal, paired with a cloud-based back office.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$How does Lavu compare to Toast?$q$, $q$Lavu is generally positioned as a more affordable, iPad-native alternative to Toast, which uses proprietary Android-based hardware and has a larger enterprise/franchise focus.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Independent restaurant point-of-sale$q$, $q$Independent restaurants use Lavu's iPad POS, kitchen display and payment processing to run day-to-day front- and back-of-house operations.$q$, $q$Independent restaurant owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Multi-location quick-service management$q$, $q$Small restaurant groups and quick-service chains use Lavu's cloud back office to manage menus, inventory and reporting across multiple locations.$q$, $q$Multi-location restaurant operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Restaurant working-capital financing$q$, $q$Operators use Lavu Capital to access working-capital advances based on their processing history without applying for a traditional bank loan.$q$, $q$Restaurant owners needing financing$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Starter$q$, $q$From ~$59-69/month per terminal$q$, $q$Monthly or annual (custom quote)$q$, NULL, $q$["Single-terminal POS","Core order management","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Growth tiers$q$, $q$~$129-249/month$q$, $q$Monthly or annual (custom quote)$q$, NULL, $q$["Multiple terminals/users","Kitchen display system","Online ordering integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$Optimize$q$, $q$~$279/month$q$, $q$Annual (custom quote)$q$, NULL, $q$["Full-featured, multi-location support","Advanced reporting","Payroll and scheduling tools"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lavu, founded in 2010 in Albuquerque, New Mexico, was one of the earliest iPad-native restaurant point-of-sale systems, built as a lower-cost, tablet-based alternative to legacy proprietary POS hardware.$q$, $q$The platform now spans order-taking, kitchen display, payments, online ordering, payroll and financing through its Lavu Capital product, aimed primarily at independent and small-chain restaurants.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lavu's core POS runs on iPads with a cloud-synced back office, offline mode for connectivity outages, and a kitchen display system that routes tickets directly to the kitchen.$q$, $q$Additional tools cover online ordering, payment processing, inventory and menu management, employee scheduling and payroll, plus an AI assistant called Marty AI for natural-language sales and operations insights.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lavu's pricing is largely quote-based, with third-party trackers reporting entry packages starting around $59-69/month per terminal, scaling up through mid-tier options as restaurants add terminals or users.$q$, $q$Higher-end packages such as the reported 'Optimize' tier run roughly $279/month billed annually for full-featured, multi-location restaurant operations, with final pricing depending on a custom quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa214254-dedb-418f-829f-a286a6fdbeb5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
